# ═══════════════════════════════════════════════════════════════════
# GENERATE JS OUTPUT
# ═══════════════════════════════════════════════════════════════════

def generate_js(concepts_dict):
    """Converts the CONCEPTS dict to a JS const string."""
    payload = json.dumps(concepts_dict, ensure_ascii=False, indent=2)
    return f"\n// ═══ CONCEPTS DATA ═══\nconst CONCEPTS={payload};\n"


def inject_into_data_js(concepts_dict, data_js_path: Path):
    text = data_js_path.read_text(encoding="utf-8", errors="ignore")

    new_block = generate_js(concepts_dict)

    # If CONCEPTS already exists — replace it
    if "const CONCEPTS=" in text:
        text = re.sub(
            r'\n// ═══ CONCEPTS DATA ═══\nconst CONCEPTS=\{[\s\S]*?\};\n',
            new_block,
            text
        )
    else:
        # Insert before REVISION CONTENT DATA
        marker = "// ═══ REVISION CONTENT DATA ═══"
        if marker in text:
            text = text.replace(marker, new_block + "\n" + marker)
        else:
            text += "\n" + new_block

    data_js_path.write_text(text, encoding="utf-8")


def count_concepts(concepts_dict):
    total = sum(len(v) for v in concepts_dict.values())
    print(f"\n✅ Concept Engine Complete!")
    print(f"   Total concepts: {total}")
    print(f"\nConcepts by subject:")
    for sid in sorted(concepts_dict.keys()):
        print(f"   {sid:6s}: {len(concepts_dict[sid])} concepts")


if __name__ == "__main__":
    import sys
    data_js = Path(sys.argv[1]) if len(sys.argv) > 1 else DEFAULT_DATA_JS
    inject_into_data_js(CONCEPTS, data_js)
    count_concepts(CONCEPTS)
    print(f"\nInjected into: {data_js}")
